from fastapi import FastAPI, HTTPException, status
from pydantic import BaseModel
from typing import Optional
import uuid

app = FastAPI(title="Bookstore REST API")

# In-memory store for illustration
books_db: dict[str, dict] = {}


# ── Data models ──────────────────────────────────────────────────────────────

class BookCreate(BaseModel):
    title: str
    author: str
    isbn: str
    year: int

class BookUpdate(BaseModel):
    title: Optional[str] = None
    author: Optional[str] = None

class Book(BookCreate):
    id: str


# ── Endpoints ─────────────────────────────────────────────────────────────────

@app.get("/books", response_model=list[Book], status_code=status.HTTP_200_OK)
def list_books():
    """GET /books — list all books."""
    return list(books_db.values())


@app.post("/books", response_model=Book, status_code=status.HTTP_201_CREATED)
def create_book(payload: BookCreate):
    """POST /books — create a new book resource."""
    book_id = str(uuid.uuid4())
    book = {"id": book_id, **payload.model_dump()}
    books_db[book_id] = book
    return book


@app.get("/books/{book_id}", response_model=Book)
def get_book(book_id: str):
    """GET /books/{id} — retrieve a single book by ID."""
    if book_id not in books_db:
        raise HTTPException(status_code=404, detail="Book not found")
    return books_db[book_id]


@app.put("/books/{book_id}", response_model=Book)
def replace_book(book_id: str, payload: BookCreate):
    """PUT /books/{id} — replace the entire book resource."""
    if book_id not in books_db:
        raise HTTPException(status_code=404, detail="Book not found")
    book = {"id": book_id, **payload.model_dump()}
    books_db[book_id] = book
    return book


@app.patch("/books/{book_id}", response_model=Book)
def update_book(book_id: str, payload: BookUpdate):
    """PATCH /books/{id} — partially update a book."""
    if book_id not in books_db:
        raise HTTPException(status_code=404, detail="Book not found")
    stored = books_db[book_id]
    updates = payload.model_dump(exclude_unset=True)
    stored.update(updates)
    return stored


@app.delete("/books/{book_id}", status_code=status.HTTP_204_NO_CONTENT)
def delete_book(book_id: str):
    """DELETE /books/{id} — remove a book."""
    if book_id not in books_db:
        raise HTTPException(status_code=404, detail="Book not found")
    del books_db[book_id]
    # 204 returns no body

