import jwt
from fastapi import HTTPException, Security, Depends
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
from datetime import datetime, timedelta, timezone

SECRET_KEY = "your-secret-key-from-env"  # Use environment variable in production
ALGORITHM = "HS256"
security = HTTPBearer()

def create_token(user_id: str, scopes: list[str]) -> str:
    payload = {
        "sub": user_id,
        "scopes": scopes,
        "exp": datetime.now(timezone.utc) + timedelta(hours=1),
        "iat": datetime.now(timezone.utc),
    }
    return jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)

def verify_token(credentials: HTTPAuthorizationCredentials = Security(security)) -> dict:
    try:
        payload = jwt.decode(credentials.credentials, SECRET_KEY, algorithms=[ALGORITHM])
        return payload
    except jwt.ExpiredSignatureError:
        raise HTTPException(status_code=401, detail="Token has expired")
    except jwt.InvalidTokenError:
        raise HTTPException(status_code=401, detail="Invalid token")

# Usage in a protected endpoint
from fastapi import FastAPI
app = FastAPI()

@app.get("/admin/users")
def admin_list_users(token_data: dict = Depends(verify_token)):
    if "admin" not in token_data.get("scopes", []):
        raise HTTPException(status_code=403, detail="Insufficient permissions")
    return [{"id": 1, "name": "Alice"}, {"id": 2, "name": "Bob"}]
